const body = $input.first().json.body;
const record = body.record;
const payload = record.payload;
const submissionId = record.id;
const email = (payload.email || '').trim().toLowerCase();
const companyName = (payload.company || '').trim();

// RULE 1: Required fields — field names confirmed from IntakeForm.tsx
const requiredFields = [
  { field: 'name', value: payload.name },
  { field: 'email', value: payload.email },
  { field: 'company', value: payload.company },
  { field: 'industry', value: payload.industry },
  { field: 'problem_in_operations', value: payload.problem_in_operations },
  { field: 'tech_stack', value: payload.tech_stack },
  { field: 'timeline', value: payload.timeline },
  { field: 'budget_range', value: payload.budget_range },
  { field: 'goals_and_outcomes', value: payload.goals_and_outcomes },
  { field: 'consent', value: payload.consent },
];
const missing = requiredFields.filter(f => {
  if (typeof f.value === 'boolean') return f.value !== true;
  return f.value === null || f.value === undefined || String(f.value).trim() === '';
});
const rule1 = {
  rule: 1, name: 'Required fields present',
  pass: missing.length === 0,
  reason: missing.length === 0
    ? 'All required fields present'
    : 'Missing or empty: ' + missing.map(f => f.field).join(', ')
};

// RULE 2: Email valid + not disposable
const DISPOSABLE_DOMAINS = [
  'mailinator.com','tempmail.com','guerrillamail.com','10minutemail.com',
  'throwaway.email','yopmail.com','temp-mail.org','getnada.com',
  'dispostable.com','maildrop.cc'
];
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const isValidFormat = emailRegex.test(email);
const emailDomain = email.split('@')[1] || '';
const isDisposable = DISPOSABLE_DOMAINS.includes(emailDomain);
const rule2 = {
  rule: 2, name: 'Email valid, not disposable',
  pass: isValidFormat && !isDisposable,
  reason: !isValidFormat ? 'Invalid email format'
    : isDisposable ? 'Disposable domain: ' + emailDomain
    : 'Email valid'
};

// RULE 4: Problem maps to a service (case-insensitive substring match)
// Keyword seed list from Spec §4.1a — do not modify without version bump
const RULE4_KEYWORDS = [
  'automate','automation','manual','repetitive','by hand','copy-paste','data entry','slow','time-consuming','tedious','rpa','robotic process','eliminate manual work',
  'integrate','integration','connect','sync','api',"doesn't talk to",'disconnected systems','silo','silos','multiple systems','migrate data','single source of truth','consolidate',
  'ai','artificial intelligence','machine learning','chatbot','agent','llm','predictive','generative','smart assistant','ai-powered','recommendation engine',
  'analytics','reporting','business intelligence','insights','kpi','metrics','data analysis','forecasting','trend','data-driven','benchmarking',
  'dashboard','real-time view','visualize','visualization','single pane of glass','live data','monitor performance','at-a-glance',
  'optimize','optimization','streamline','bottleneck','slow','inefficient','efficiency','process improvement','restructure process','simplify process'
];
const problemText = (payload.problem_in_operations || '').toLowerCase();
const matchedKeyword = RULE4_KEYWORDS.find(kw => problemText.includes(kw.toLowerCase()));
const rule4 = {
  rule: 4, name: 'Problem maps to a service',
  pass: !!matchedKeyword,
  reason: matchedKeyword ? 'Matched keyword: ' + matchedKeyword : 'No service keyword matched in problem_in_operations'
};

// RULE 5: Budget not 'exploring'
// Literal form value from IntakeForm.tsx BUDGET_OPTIONS
const budget = (payload.budget_range || '').trim();
const rule5 = {
  rule: 5, name: 'Budget not exploring',
  pass: budget !== 'exploring',
  reason: budget === 'exploring' ? 'Budget is exploring (no budget set)' : 'Budget: ' + budget
};

// RULE 6: Timeline not 'no urgency'
// Literal §4.2 enum value, matching frontend TIMELINE_OPTIONS
const timeline = (payload.timeline || '').trim();
const rule6 = {
  rule: 6, name: 'Timeline not no urgency',
  pass: timeline !== 'no urgency',
  reason: timeline === 'no urgency' ? 'Timeline is no urgency' : 'Timeline: ' + timeline
};

// RULE 7: Tech stack disclosed
const techStack = (payload.tech_stack || '').trim();
const rule7 = {
  rule: 7, name: 'Tech stack disclosed',
  pass: techStack !== '' && techStack.toLowerCase() !== 'skip',
  reason: techStack === '' ? 'Tech stack is empty'
    : techStack.toLowerCase() === 'skip' ? 'Tech stack is skip'
    : 'Tech stack provided'
};

return [{ json: { submissionId, record, payload, email, companyName, partialRules: [rule1, rule2, rule4, rule5, rule6, rule7] } }];

const phase1 = $('Phase 1: Evaluate Rules').first().json;
const rule3Resp = $('Rule 3: Check Duplicate Email').first().json;
const companyResp = $('Lookup Company').first().json;

// fullResponse format: { statusCode, headers, body }
const rule3Body = Array.isArray(rule3Resp.body) ? rule3Resp.body : [];
const companyBody = Array.isArray(companyResp.body) ? companyResp.body : [];

const existingProspectId = rule3Body.length > 0 ? rule3Body[0].id : null;
const existingCompanyId = companyBody.length > 0 ? companyBody[0].id : null;

const rule3 = {
  rule: 3, name: 'No duplicate prospect',
  pass: existingProspectId === null,
  reason: existingProspectId !== null
    ? 'Existing prospect found: ' + existingProspectId
    : 'No existing prospect with this email'
};

// All 7 rules in spec order — look up by rule tag, not position
const findRule = (n) => phase1.partialRules.find(r => r.rule === n);
const allRules = [1,2,3,4,5,6,7].map(n => n === 3 ? rule3 : findRule(n));

const threshold = parseInt($env.QUALIFICATION_THRESHOLD) || 6;
const passCount = allRules.filter(r => r.pass).length;
const qualified = passCount >= threshold;
const failedRules = allRules.filter(r => !r.pass).map(r => r.name);
const reason = qualified
  ? 'Qualified: ' + passCount + '/7 rules passed'
  : 'Not qualified: ' + passCount + '/7 rules passed. Failed: ' + failedRules.join(', ');

return [{ json: {
  ...phase1,
  existingProspectId,
  existingCompanyId,
  isNewCompany: existingCompanyId === null,
  isExistingProspect: existingProspectId !== null,
  allRules,
  qualified,
  reason,
  passCount,
  threshold
} }];

const item = $input.first().json;
// Use Existing Company path: company_id already set
// Create Company path (HTTP fullResponse): body is [{id, name, ...}]
let company_id;
if (item.company_id) {
  company_id = item.company_id;
} else if (item.body && Array.isArray(item.body) && item.body.length > 0) {
  company_id = item.body[0].id;
}
// Rebuild full context (Create Company path loses phase1 data)
const base = $('Finalize Qualification').first().json;
return [{ json: { ...base, company_id } }];

const item = $input.first().json;
// INSERT succeeded: fullResponse body is [{id, full_name, email, ...}]
const prospect_id = item.body && Array.isArray(item.body) && item.body.length > 0
  ? item.body[0].id
  : null;
const base = $('Set Company ID').first().json;
return [{ json: { ...base, prospect_id } }];
